// Generated by SKILL-ASTRO (W8 #282). CMS=sanity.
// On-publish webhook handler. Sanity POSTs here every time an editor
// publishes; we verify the HMAC signature and bust any caches that
// reference the affected document. In SSG mode an operator would
// chain this to a rebuild trigger (Vercel/Cloudflare deploy hook);
// in SSR mode we invalidate CDN tags.

import type { APIRoute } from "astro"
import { verifyWebhook } from "../../../lib/cms/sanity"

export const prerender = false

export const POST: APIRoute = async ({ request }) => {
  const signature = request.headers.get("sanity-webhook-signature")
  const rawBody = await request.text()
  const ok = await verifyWebhook(signature, rawBody)
  if (!ok) {
    return new Response(JSON.stringify({ ok: false, reason: "invalid-signature" }), {
      status: 401,
      headers: { "Content-Type": "application/json" },
    })
  }
  let payload: unknown = null
  try {
    payload = JSON.parse(rawBody)
  } catch {
    return new Response(JSON.stringify({ ok: false, reason: "invalid-json" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    })
  }
  // TODO(operator): wire this to the rebuild hook (Vercel deploy
  // hook, Cloudflare deploy_hook, or in SSR mode CDN cache-tag
  // invalidation). For now we ack the webhook so Sanity stops
  // retrying.
  return new Response(
    JSON.stringify({ ok: true, received: (payload as { _id?: string } | null)?._id ?? null }),
    {
      status: 200,
      headers: { "Content-Type": "application/json" },
    },
  )
}
